// Filtrar apenas membros com status 'ativo'
// Ignorar cancelados e inadimplentes
const membrosAtivos = $input.all().filter(item => {
  const s = (item.json.status || '').toLowerCase();
  return s === 'ativo';
});

console.log(`Total membros ativos: ${membrosAtivos.length}`);
return membrosAtivos;

// Para cada membro ativo, calcular quantos dias se passaram desde data_entrada
// e determinar qual fase (se alguma) deve ser disparada agora.

const hoje = new Date();
hoje.setHours(0, 0, 0, 0);
const hojeISO = hoje.toISOString().split('T')[0];

const acoes = [];

for (const item of $input.all()) {
  const m = item.json;
  const nome = m.nome_membro || 'Membro';
  const fone = (m.whatsapp || '').replace(/\D/g, '');
  const plano = m.plano || 'individual';
  const valor = m.valor_mensalidade || '39,90';

  if (!fone) continue;

  // Calcular dias desde entrada
  let diasDesdeEntrada = -1;
  if (m.data_entrada) {
    const entrada = new Date(m.data_entrada);
    entrada.setHours(0, 0, 0, 0);
    diasDesdeEntrada = Math.floor((hoje - entrada) / (1000 * 60 * 60 * 24));
  }

  // D+0 — novo membro (onboarding não iniciado)
  if (!m.onboarding_iniciado || m.onboarding_iniciado === 'FALSE') {
    acoes.push({ fase: 'D0_BOAS_VINDAS', ...m, nome, fone, plano, valor, diasDesdeEntrada });
    acoes.push({ fase: 'D0_ALERTA_KARINE', ...m, nome, fone, plano, valor, diasDesdeEntrada });
    continue; // só iniciar o onboarding, as fases seguintes virão nos próximos dias
  }

  if (diasDesdeEntrada < 0) continue;

  // D+3 — dica de uso
  if (diasDesdeEntrada >= 3 && !m.data_d3_enviado) {
    acoes.push({ fase: 'D3', ...m, nome, fone, plano, valor, diasDesdeEntrada });
  }

  // D+7 — urgência leve
  if (diasDesdeEntrada >= 7 && !m.data_d7_enviado) {
    acoes.push({ fase: 'D7', ...m, nome, fone, plano, valor, diasDesdeEntrada });
  }

  // D+15 — toque humano (Karine faz manualmente: gerar alerta Notion)
  if (diasDesdeEntrada >= 15 && !m.data_d15_alerta) {
    acoes.push({ fase: 'D15_ALERTA_NOTION', ...m, nome, fone, plano, valor, diasDesdeEntrada });
  }

  // D+25 — alerta renovação
  if (diasDesdeEntrada >= 25 && !m.data_d25_enviado) {
    acoes.push({ fase: 'D25', ...m, nome, fone, plano, valor, diasDesdeEntrada });
  }

  // D+30 — NPS
  if (diasDesdeEntrada >= 30 && !m.data_d30_enviado) {
    acoes.push({ fase: 'D30', ...m, nome, fone, plano, valor, diasDesdeEntrada });
  }
}

console.log(`Ações a executar: ${acoes.length}`);
return acoes.map(a => ({ json: a }));

// Montar a mensagem certa para cada fase
const acao = $input.first().json;
const nome = acao.nome;
const valor = acao.valor;
const fase = acao.fase;
const fone = acao.fone;

const mensagens = {
  D0_BOAS_VINDAS: `Bem-vindo(a) à família SST Card, ${nome}! 🎉

Seu cartão já tá ativo. Aqui vai o que você tem acesso:
✅ Consultas médicas incluídas
✅ Laboratório com desconto especial
✅ Exames de rotina
✅ Telemedicina

Pra usar: é só vir na SST Clínica e apresentar o CPF. Simples assim.
Qualquer dúvida, me chama aqui. Sou a Karine 😊`,

  D0_ALERTA_KARINE: `🔔 *Novo membro ativado!*

👤 *${nome}*
📱 ${fone}
💳 Plano: ${acao.plano || 'Individual'}

⚡ Entrar em contato em até 2h para agendar a primeira consulta.
Membro que usa na 1ª semana tem 85% de renovação!`,

  D3: `Oi ${nome}! Karine aqui 😊

Sabia que consulta de rotina é o melhor jeito de usar o SST Card? Muita gente deixa pra quando tá doente — mas o cartão foi feito pra antes disso.

Você tem algum exame ou consulta atrasada? Posso te ajudar a agendar agora.`,

  D7: `${nome}, já faz uma semana com seu SST Card! 🎊

Você já usou algum serviço? Se não usou ainda, não perde tempo — marque uma consulta essa semana e já aproveita o que é seu.

Agenda pelo WhatsApp: é só me chamar aqui.`,

  D25: `${nome}, sua mensalidade do SST Card vence em 5 dias.

Pra não perder o acesso, você pode:
💳 Pix: [chave Pix SST]
💳 Débito: presencialmente na clínica

Dúvida? Me chama que resolvo agora. — Karine`,

  D30: `${nome}, um mês com o SST Card! 🥳

Queria saber: de 1 a 5, qual nota você dá pra nossa clínica?
Responde aqui com o número — leva 5 segundos e ajuda muito a gente.

1 = Muito ruim | 5 = Excelente`
};

const destino = fase === 'D0_ALERTA_KARINE' 
  ? $env.KARINE_WHATSAPP   // número pessoal da Karine
  : fone;                   // número do membro

const texto = mensagens[fase];

if (!texto) return [];  // fase não mapeada, ignorar

return [{ json: { ...acao, mensagem: texto, destino } }];

// Atualizar colunas de controle no Sheets após envio
const acao = $input.first().json;
const hoje = new Date().toISOString().split('T')[0];
const fase = acao.fase;

// Mapear fase → coluna que precisa ser atualizada
const mapeamento = {
  D0_BOAS_VINDAS:    { onboarding_iniciado: 'TRUE', data_entrada: hoje, data_d0_enviado: hoje },
  D0_ALERTA_KARINE:  {},  // sem atualização extra (D0_BOAS_VINDAS já marca onboarding)
  D3:                { data_d3_enviado: hoje },
  D7:                { data_d7_enviado: hoje },
  D25:               { data_d25_enviado: hoje },
  D30:               { data_d30_enviado: hoje }
};

const atualizacoes = mapeamento[fase] || {};

return [{ json: { ...acao, atualizacoes, hoje } }];

